#ifndef KERNEL_H
#define KERNEL_H

#include <cuda_runtime.h>
#include <cuda_fp16.h>

// Forward declaration for the kernel launch function
// Optimized for A800 (Hopper) architecture with specific constant dimensions
void launch_gemm_kernel(half* A, half* B, half* C, int M, int N, int K, cudaStream_t stream);

#endif // KERNEL_H

#include "kernel.h"

// Specification Constants
// N is constant 28672, K is constant 4096
constexpr int CONST_N = 28672;
constexpr int CONST_K = 4096;

// Block Dimensions optimized for A800
// 16x16 threads per block - 256 threads total for better occupancy
constexpr int BLOCK_X = 16;
constexpr int BLOCK_Y = 16;

// Tile size for K dimension
// 64 is a good balance between shared memory usage and loop iterations
// Each thread loads TILE_K / BLOCK_X = 4 elements from K for A
// Each thread loads TILE_K / BLOCK_Y = 4 elements from K for B
constexpr int TILE_K = 64;

// Shared Memory Size:
// A_tile: 16 * 64 * 2 bytes = 2 KB
// B_tile: 64 * 16 * 2 bytes = 2 KB
// Total: 4 KB (Well within A800 128 KB per SM)

__global__ void gemm_kernel(half* A, half* B, half* C, int M, int N, int K) {
    // Thread indices within block
    int tx = threadIdx.x;
    int ty = threadIdx.y;

    // Block indices
    int bx = blockIdx.x;
    int by = blockIdx.y;

    // Global indices for Output C [M, N]
    // Each thread computes one element of C
    int row = by * BLOCK_Y + ty;  // M dimension
    int col = bx * BLOCK_X + tx;  // N dimension

    // Accumulator in FP32 for precision (A800 Tensor Core standard practice)
    float acc = 0.0f;

    // Shared Memory Tiles
    // A_tile: [BLOCK_Y, TILE_K] -> Stores A[row][k] for this block's rows
    // B_tile: [TILE_K, BLOCK_X] -> Stores B[col][k] transposed for efficient access
    __shared__ half A_tile[BLOCK_Y][TILE_K];
    __shared__ half B_tile[TILE_K][BLOCK_X];

    // Loop over K dimension in tiles
    for (int k = 0; k < K; k += TILE_K) {
        // Load A tile into shared memory
        // A is [M, K], row-major: A[row * K + (k + tx)]
        // Each thread loads TILE_K / BLOCK_X = 4 elements from K dimension
        for (int t = 0; t < TILE_K; t += BLOCK_X) {
            int k_offset = k + t + tx;
            if (row < M && k_offset < K) {
                A_tile[ty][t + tx] = A[row * K + k_offset];
            } else {
                A_tile[ty][t + tx] = __float2half(0.0f);
            }
        }

        // Load B tile into shared memory (transposed layout)
        // B is [N, K], row-major: B[col * K + (k + ty)]
        // Each thread loads TILE_K / BLOCK_Y = 4 elements from K dimension
        for (int t = 0; t < TILE_K; t += BLOCK_Y) {
            int k_offset = k + t + ty;
            if (col < N && k_offset < K) {
                B_tile[t + ty][tx] = B[col * K + k_offset];
            } else {
                B_tile[t + ty][tx] = __float2half(0.0f);
            }
        }

        // Ensure all loads are complete before computation
        __syncthreads();

        // Compute partial dot product for this K-tile
        // ty is Row-offset, tx is Col-offset, t is K-offset
        #pragma unroll
        for (int t = 0; t < TILE_K; t++) {
            half a_val = A_tile[ty][t];
            half b_val = B_tile[t][tx];
            acc += __half2float(a_val) * __half2float(b_val);
        }

        // Ensure computation is complete before next load
        __syncthreads();
    }

    // Write result to global memory
    if (row < M && col < N) {
        C[row * N + col] = __float2half(acc);
    }
}

void launch_gemm_kernel(half* A, half* B, half* C, int M, int N, int K, cudaStream_t stream) {
    // Validate fixed dimensions against specification
    if (N != CONST_N || K != CONST_K) {
        // Kernel is optimized for these constants, mismatch may lead to undefined behavior
        // In production, you might want to assert or throw here
    }

    // Define Grid Dimensions
    // X covers N (28672), Y covers M (Variable)
    dim3 block(BLOCK_X, BLOCK_Y);
    dim3 grid((N + BLOCK_X - 1) / BLOCK_X, (M + BLOCK_Y - 1) / BLOCK_Y);

    // Launch Kernel
    gemm_kernel<<<grid, block, 0, stream>>>(A, B, C, M, N, K);
}

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include "kernel.h"
#include <stdexcept>
#include <string>

// Helper to check CUDA errors
inline void check_cuda_error(cudaError_t error, const char* msg) {
    if (error != cudaSuccess) {
        throw std::runtime_error(std::string(msg) + ": " + cudaGetErrorString(error));
    }
}

// Host function to execute the GEMM operation
// Optimized for A800 GPU with PyTorch bindings
// Supports both 2-argument and 3-argument calling conventions
torch::Tensor run(torch::Tensor A, torch::Tensor B, torch::Tensor C = torch::Tensor()) {
    // 1. Validate Input Properties
    if (!A.is_cuda() || !B.is_cuda()) {
        throw std::runtime_error("Inputs must be on CUDA device");
    }
    if (A.dtype() != torch::kHalf || B.dtype() != torch::kHalf) {
        throw std::runtime_error("Inputs must be of dtype FLOAT16");
    }
    if (A.dim() != 2 || B.dim() != 2) {
        throw std::runtime_error("Inputs must be 2D tensors");
    }

    int M = A.size(0);
    int K = A.size(1);
    int N = B.size(0);
    int K_B = B.size(1);

    // Validate shapes match specification (N=28672, K=4096)
    if (N != 28672) {
        throw std::runtime_error("Dimension N must be 28672, got " + std::to_string(N));
    }
    if (K != 4096 || K_B != 4096) {
        throw std::runtime_error("Dimension K must be 4096, got A.K=" + std::to_string(K) + ", B.K=" + std::to_string(K_B));
    }
    if (K != K_B) {
        throw std::runtime_error("Inner dimensions of A and B must match");
    }

    // 2. Allocate or use provided Output Tensor C [M, N]
    // If C is provided and valid, use it; otherwise allocate new
    if (C.defined() && C.numel() > 0) {
        // Validate provided C tensor
        if (!C.is_cuda()) {
            throw std::runtime_error("Output tensor C must be on CUDA device");
        }
        if (C.dtype() != torch::kHalf) {
            throw std::runtime_error("Output tensor C must be of dtype FLOAT16");
        }
        if (C.size(0) != M || C.size(1) != N) {
            throw std::runtime_error("Output tensor C must have shape [M, N] = [" + 
                                     std::to_string(M) + ", " + std::to_string(N) + "]");
        }
    } else {
        // Allocate new output tensor
        C = torch::empty({M, N}, A.options());
    }

    // 3. Extract Raw Pointers
    // Use reinterpret_cast for at::Half to half conversion (memory-compatible types)
    half* d_A = reinterpret_cast<half*>(A.data_ptr<at::Half>());
    half* d_B = reinterpret_cast<half*>(B.data_ptr<at::Half>());
    half* d_C = reinterpret_cast<half*>(C.data_ptr<at::Half>());

    // 4. Get CUDA Stream
    cudaStream_t stream = at::cuda::getCurrentCUDAStream();

    // 5. Launch Kernel
    launch_gemm_kernel(d_A, d_B, d_C, M, N, K, stream);

    // 6. Synchronize and Check Errors
    check_cuda_error(cudaGetLastError(), "Kernel launch failed");
    check_cuda_error(cudaStreamSynchronize(stream), "Stream synchronization failed");

    return C;
}

// PyBind11 Module Definition
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.doc() = "CUDA GEMM Extension for A800";
    // Bind the run function with named arguments support for kwargs
    m.def("run", &run, "Executes GEMM (A @ B.T) optimized for A800",
          py::arg("A"),
          py::arg("B"),
          py::arg("C") = torch::Tensor());
}
